def gaussian_pdf(x: Float64, mu: Float64, sigma: Float64) -> Float64:
    var d = (x - mu) / sigma
    var pi = 3.14159265358979323846
    return exp(-0.5 * d * d) / (sigma * sqrt(2.0 * pi))

