def coeff_variation(a: Float64, b: Float64, c: Float64, d: Float64) -> Float64:
    var m = (a + b + c + d) / 4.0
    var s = (a - m) * (a - m) + (b - m) * (b - m) + (c - m) * (c - m) + (d - m) * (d - m)
    var sd = sqrt(s / 4.0)
    return sd / m

