def cosine_similarity2d(ax: Float64, ay: Float64, bx: Float64, by: Float64) -> Float64:
    var dot = ax * bx + ay * by
    var na = sqrt(ax * ax + ay * ay)
    var nb = sqrt(bx * bx + by * by)
    return dot / (na * nb)

def chebyshev3d(x1: Float64, y1: Float64, z1: Float64, x2: Float64, y2: Float64, z2: Float64) -> Float64:
    var dx = abs(x2 - x1)
    var dy = abs(y2 - y1)
    var dz = abs(z2 - z1)
    var m = dx
    if dy > m:
        m = dy
    if dz > m:
        m = dz
    return m

